import type { Metadata } from "next";
import CardStatement from "./CardStatement";

export const metadata: Metadata = {
  title: "クレジットカードご利用明細 | ぐんじょうカード",
  description:
    "今回のお支払い金額、ご利用可能額、ポイント、カテゴリ別ご利用、ご利用明細を確認できます。",
