/**
 * Mock data + domain helpers for the クレジットカード利用明細 screen.
 * Kept framework-free so the page logic stays declarative.
 */

export type PaymentType = "ikkatsu" | "bunkatsu" | "ribo";

export interface Charge {
  id: string;
  date: string; // ISO ご利用日
  merchant: string; // ご利用先
  category: CategoryKey;
  payment: PaymentType; // 支払区分
  amount: number; // ご利用金額 (¥)
  installments?: number; // 分割回数 (for 分割)
}

export type CategoryKey =
  | "shopping"
  | "groceries"
  | "transport"
  | "utilities"
  | "travel"
  | "dining"
  | "entertainment";

export const CATEGORY_LABELS: Record<CategoryKey, string> = {
  shopping: "ショッピング",
  groceries: "食料品",
  transport: "交通",
  utilities: "公共料金",
  travel: "旅行",
  dining: "外食",
  entertainment: "娯楽",
};

/** Semantic chart tone per category (tokens, not hex). */
export const CATEGORY_TONE: Record<
  CategoryKey,
  "primary" | "success" | "warning" | "info" | "accent" | "destructive"
> = {
  shopping: "primary",
  groceries: "success",
  transport: "info",
  utilities: "warning",
  travel: "accent",
  dining: "destructive",
  entertainment: "primary",
};

export const PAYMENT_LABELS: Record<PaymentType, string> = {
  ikkatsu: "一括",
  bunkatsu: "分割",
  ribo: "リボ",
};

/** Badge variant per 支払区分 — text label means it is never colour-only. */
export const PAYMENT_BADGE: Record<
  PaymentType,
  "secondary" | "info" | "warning"
> = {
  ikkatsu: "secondary",
  bunkatsu: "info",
  ribo: "warning",
};

export interface StatementPeriod {
  key: string; // YYYY-MM
  label: string; // 2026年6月
  closingDate: string; // 締め日
  paymentDate: string; // お支払日
  /** Default 支払い方法 for this statement. */
  defaultMethod: PaymentType;
  charges: Charge[];
}

/* ------------------------------------------------------------------ */
/* Card / credit-line facts (shared across periods)                    */
/* ------------------------------------------------------------------ */

export const CARD = {
  brand: "GUNJO VISA Gold",
  maskedNumber: "•••• 4321",
  holder: "ケ エエム 様",
  creditLimit: 1_000_000, // 利用可能枠
  /** Carried (revolving) balance not tied to this month's new charges. */
  carriedBalance: 80_000,
} as const;

export const POINTS = {
