/* ------------------------------------------------------------------ */
/* Statement periods                                                   */
/* ------------------------------------------------------------------ */

function charge(
  id: string,
  date: string,
  merchant: string,
  category: CategoryKey,
  payment: PaymentType,
  amount: number,
  installments?: number,
): Charge {
  return { id, date, merchant, category, payment, amount, installments };
}

