];

export const PERIODS: StatementPeriod[] = [
  {
    key: "2026-06",
    label: "2026年6月",
    closingDate: "2026-06-30",
    paymentDate: "2026-07-27",
    defaultMethod: "ikkatsu",
    charges: JUNE_CHARGES,
  },
  {
    key: "2026-05",
    label: "2026年5月",
    closingDate: "2026-05-31",
    paymentDate: "2026-06-27",
    defaultMethod: "ikkatsu",
    charges: MAY_CHARGES,
  },
  {
    key: "2026-04",
    label: "2026年4月",
    closingDate: "2026-04-30",
    paymentDate: "2026-05-27",
    defaultMethod: "ribo",
    charges: [], // empty-state demo (ご利用がありません)
  },
];

/* ------------------------------------------------------------------ */
/* Derived helpers (pure)                                              */
/* ------------------------------------------------------------------ */

export function chargesTotal(charges: Charge[]): number {
  return charges.reduce((sum, c) => sum + c.amount, 0);
}

export interface CategoryBreakdown {
  category: CategoryKey;
  label: string;
  amount: number;
  ratio: number; // 0..1 of total
}

export function categoryBreakdown(charges: Charge[]): CategoryBreakdown[] {
  const total = chargesTotal(charges) || 1;
  const byCat = new Map<CategoryKey, number>();
  for (const c of charges) {
    byCat.set(c.category, (byCat.get(c.category) ?? 0) + c.amount);
  }
  return [...byCat.entries()]
    .map(([category, amount]) => ({
      category,
      label: CATEGORY_LABELS[category],
      amount,
      ratio: amount / total,
    }))
    .sort((a, b) => b.amount - a.amount);
}

/* -- Payment-method fee model (illustrative, like a real issuer) -- */

/** Annual rates used to derive 手数料 (illustrative). */
export const RIBO_ANNUAL_RATE = 0.15; // 実質年率 15.0%
export const BUNKATSU_RATE_BY_COUNT: Record<number, number> = {
  3: 0.0202,
  6: 0.0408,
  10: 0.0681,
  12: 0.0815,
};

export interface MethodQuote {
  method: PaymentType;
  /** First month's billed amount. */
  firstPayment: number;
  /** Total fee (手数料) across the plan. */
  fee: number;
  /** Human note about the structure. */
  note: string;
}

/**
 * Quote what switching this statement's *new charges total* to a given method
 * would cost. `ribo` assumes a 10,000-yen monthly course; `bunkatsu` uses the
 * rate table for the chosen count.
 */
export function quoteMethod(
  newChargesTotal: number,
  method: PaymentType,
  bunkatsuCount = 6,
  riboMonthlyCourse = 10_000,
): MethodQuote {
  if (method === "ikkatsu") {
    return {
      method,
      firstPayment: newChargesTotal,
      fee: 0,
      note: "手数料はかかりません。締め日翌月に全額をお支払いいただきます。",
    };
  }
  if (method === "bunkatsu") {
    const rate = BUNKATSU_RATE_BY_COUNT[bunkatsuCount] ?? 0.0408;
    const fee = Math.round(newChargesTotal * rate);
    const firstPayment = Math.round((newChargesTotal + fee) / bunkatsuCount);
    return {
      method,
      firstPayment,
      fee,
      note: `${bunkatsuCount}回払い・100円あたり手数料 ${(
        (rate / bunkatsuCount) *
        100 *
        100
      ).toFixed(2)}円相当。`,
    };
  }
  // ribo — 残高スライド方式の簡易モデル
  const monthlyFee = Math.round((newChargesTotal * RIBO_ANNUAL_RATE) / 12);
  const fee = monthlyFee; // 初月分の手数料目安
  return {
    method,
    firstPayment: riboMonthlyCourse + monthlyFee,
    fee,
    note: `毎月のお支払いコース ${riboMonthlyCourse.toLocaleString(
      "ja-JP",
    )}円 + 手数料 (実質年率 ${(RIBO_ANNUAL_RATE * 100).toFixed(1)}%)。`,
  };
}

export function formatJpDate(iso: string): string {
  const d = new Date(iso + "T00:00:00");
  return `${d.getFullYear()}年${d.getMonth() + 1}月${d.getDate()}日`;
}

export function formatJpDateShort(iso: string): string {
  const d = new Date(iso + "T00:00:00");
  return `${d.getMonth() + 1}/${d.getDate()}`;
}

"use client";

import * as React from "react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Container,
  DonutChart,
  GaugeChart,
  SegmentedGaugeCard,
  Select,
  Separator,
  Skeleton,
  Statistic,
  ThemeProvider,
  formatCurrency,
  formatNumber,
  formatPercent,
} from "@gunjo/ui";
import {
  IconAlertTriangle,
  IconClockHour4,
  IconCreditCard,
  IconSparkles,
} from "@tabler/icons-react";
import StatementTable from "./StatementTable";
import PaymentMethodDialog from "./PaymentMethodDialog";
import {
  CARD,
  CATEGORY_TONE,
  POINTS,
  PERIODS,
  categoryBreakdown,
  chargesTotal,
  formatJpDate,
  quoteMethod,
  type PaymentType,
} from "./card-data";

/* ================================================================== */
/* Loading skeleton concept                                            */
/* ================================================================== */

function StatementSkeleton() {
  return (
    <div className="flex flex-col gap-6" aria-hidden="true">
      <Skeleton className="h-40 w-full rounded-xl" />
      <div className="grid gap-6 lg:grid-cols-2">
        <Skeleton className="h-64 w-full rounded-xl" />
        <Skeleton className="h-64 w-full rounded-xl" />
      </div>
      <Skeleton className="h-80 w-full rounded-xl" />
    </div>
  );
}

/* ================================================================== */
/* Inner — has all the state                                           */
/* ================================================================== */

function CardStatementInner() {
  const [periodKey, setPeriodKey] = React.useState(PERIODS[0].key);
  const [loading, setLoading] = React.useState(false);
  const [method, setMethod] = React.useState<PaymentType>(PERIODS[0].defaultMethod);

  const period = React.useMemo(
    () => PERIODS.find((p) => p.key === periodKey) ?? PERIODS[0],
    [periodKey],
  );

  // Switching months: reset the chosen method to the period default and show a
  // brief skeleton, the way a real client refetches a statement.
  function changePeriod(nextKey: string) {
    setLoading(true);
    setPeriodKey(nextKey);
    setMethod(
      PERIODS.find((p) => p.key === nextKey)?.defaultMethod ?? "ikkatsu",
    );
    window.setTimeout(() => setLoading(false), 450);
  }

  const newChargesTotal = React.useMemo(
    () => chargesTotal(period.charges),
    [period],
  );

  // 今回お支払い金額 = この月の新規ご利用 (選択中の支払区分で再計算) + 繰越残高
  const methodQuote = React.useMemo(
    () => quoteMethod(newChargesTotal, method),
    [newChargesTotal, method],
  );
  const billThisMonth =
    method === "ikkatsu"
      ? newChargesTotal + CARD.carriedBalance
      : methodQuote.firstPayment + CARD.carriedBalance;

  // 利用額 vs 利用可能枠 — used = carried balance + this month's new charges.
  const used = CARD.carriedBalance + newChargesTotal;
  const remaining = Math.max(CARD.creditLimit - used, 0);
  const usedRatio = used / CARD.creditLimit;
  const nearLimit = usedRatio >= 0.8;
  const overHalf = usedRatio >= 0.5;

  const breakdown = React.useMemo(
    () => categoryBreakdown(period.charges),
    [period],
  );

  const yen = (v: number) => formatCurrency(v);

  return (
    <main className="min-h-full bg-background py-8 sm:py-10">
      <Container size="lg" className="flex flex-col gap-8">
        {/* ---- Page header (the single <h1>) ---- */}
        <header className="flex flex-col gap-3">
          <div className="flex items-center gap-2 text-sm text-muted-foreground">
            <IconCreditCard aria-hidden size={18} />
            <span>ぐんじょうカード</span>
          </div>
          <h1 className="text-2xl font-bold tracking-tight text-foreground sm:text-3xl">
            クレジットカードご利用明細
          </h1>
          <p className="max-w-2xl text-sm text-muted-foreground">
            今回のお支払い金額、ご利用可能額、ポイント、カテゴリ別のご利用、そして明細を確認できます。
          </p>

          {/* Month/period selector — native <select>, announced + keyboard */}
          <div className="mt-1 max-w-xs">
            <Select
              label="ご請求月"
              value={periodKey}
              onChange={(e) => changePeriod(e.target.value)}
            >
              {PERIODS.map((p) => (
                <option key={p.key} value={p.key}>
                  {p.label}
                  {p.charges.length === 0 ? "（ご利用なし）" : ""}
                </option>
              ))}
            </Select>
          </div>
        </header>

        {loading ? (
          <StatementSkeleton />
        ) : (
          <>
            {/* ============ Card summary ============ */}
            <section aria-labelledby="summary-heading">
              <h2 id="summary-heading" className="sr-only">
                カード概要
              </h2>
              <Card className="overflow-hidden">
                <div className="grid gap-0 md:grid-cols-[1.1fr_1fr]">
                  {/* Brand / masked number / holder */}
                  <div className="flex flex-col justify-between gap-6 bg-primary/5 p-6">
                    <div className="flex items-start justify-between gap-4">
                      <div>
                        <p className="text-sm font-medium text-muted-foreground">
                          {CARD.brand}
                        </p>
                        <p
                          className="mt-2 font-mono text-lg tracking-widest text-foreground"
                          aria-label="カード番号 下4桁 4321"
                        >
                          {CARD.maskedNumber}
                        </p>
                      </div>
                      <IconCreditCard
                        aria-hidden
                        size={32}
                        className="text-primary"
                      />
                    </div>
                    <dl className="grid grid-cols-2 gap-4 text-sm">
                      <div>
                        <dt className="text-xs text-muted-foreground">会員名</dt>
                        <dd className="font-medium text-foreground">
                          {CARD.holder}
                        </dd>
                      </div>
                      <div>
                        <dt className="text-xs text-muted-foreground">
                          現在の支払区分
                        </dt>
                        <dd>
                          <Badge
                            variant={
                              method === "ikkatsu"
                                ? "secondary"
                                : method === "bunkatsu"
                                  ? "info"
                                  : "warning"
                            }
                          >
                            {method === "ikkatsu"
                              ? "一括"
                              : method === "bunkatsu"
                                ? "分割"
                                : "リボ"}
                          </Badge>
                        </dd>
                      </div>
                    </dl>
                  </div>

                  {/* Bill amount + dates + change-method control */}
                  <div className="flex flex-col justify-between gap-5 p-6">
                    <div>
                      <p className="text-sm font-medium text-muted-foreground">
                        今回のお支払い金額
                      </p>
                      <p className="mt-1 text-4xl font-bold tracking-tight text-foreground tabular-nums">
                        {yen(billThisMonth)}
                      </p>
                      <p className="mt-1 text-xs text-muted-foreground">
                        うち繰越残高 {yen(CARD.carriedBalance)}
                        {method !== "ikkatsu" &&
                          ` ・ 手数料 ${yen(methodQuote.fee)}`}
                      </p>
                    </div>

                    <dl className="grid grid-cols-2 gap-4 text-sm">
                      <div>
                        <dt className="text-xs text-muted-foreground">締め日</dt>
                        <dd className="font-medium text-foreground tabular-nums">
                          {formatJpDate(period.closingDate)}
                        </dd>
                      </div>
                      <div>
                        <dt className="text-xs text-muted-foreground">
                          お支払日
                        </dt>
                        <dd className="font-medium text-foreground tabular-nums">
                          {formatJpDate(period.paymentDate)}
                        </dd>
                      </div>
                    </dl>

                    {period.charges.length > 0 && (
                      <div>
                        <PaymentMethodDialog
                          newChargesTotal={newChargesTotal}
                          current={method}
                          onApply={setMethod}
                        />
                      </div>
                    )}
                  </div>
                </div>
              </Card>
            </section>

            {/* ============ Credit gauge + Points ============ */}
            <section
              aria-labelledby="credit-heading"
              className="grid gap-6 lg:grid-cols-2"
            >
              <h2 id="credit-heading" className="sr-only">
                ご利用可能額とポイント
              </h2>

              {/* --- Credit-limit gauge (signature widget) --- */}
              <SegmentedGaugeCard
                title="ご利用可能額"
                description="ご利用枠に対する現在のご利用状況"
                segments={[
                  {
                    label: "ご利用額",
                    value: used,
                    color: nearLimit
                      ? "destructive"
                      : overHalf
                        ? "warning"
                        : "primary",
                  },
                  { label: "ご利用可能額", value: remaining, color: "muted" },
                ]}
                max={CARD.creditLimit}
                value={used}
                valueLabel={yen(remaining)}
                centerLabel="ご利用可能額"
                caption={
                  <span className="tabular-nums">
                    ご利用 {yen(used)} / 利用可能枠 {yen(CARD.creditLimit)}（
                    {formatPercent(usedRatio)} 使用）
                  </span>
                }
                formatValue={(v) => formatCurrency(v)}
                totalLabel="利用可能枠"
              />

              {/* --- Points / loyalty panel (hand-rolled, see FINDINGS) --- */}
              <Card>
                <CardHeader>
                  <div className="flex items-center justify-between gap-2">
                    <div>
                      <CardTitle as="h3" className="text-base">
                        ポイント
                      </CardTitle>
                      <CardDescription>
                        ぐんじょうポイントの残高と獲得状況
                      </CardDescription>
                    </div>
                    <IconSparkles
                      aria-hidden
                      size={22}
                      className="text-primary"
                    />
                  </div>
                </CardHeader>
                <CardContent className="flex flex-col gap-4">
                  <div className="grid grid-cols-2 gap-4">
                    <Statistic
                      label="ポイント残高"
                      value={`${formatNumber(POINTS.balance)} pt`}
                    />
                    <Statistic
                      label="今月の獲得"
                      value={`${formatNumber(POINTS.earnedThisMonth)} pt`}
                      change={`+${formatNumber(POINTS.earnedThisMonth)}`}
                      trend="up"
                      tone="positive"
                    />
                  </div>
                  <Separator />
                  <Alert variant="warning">
                    <IconClockHour4 aria-hidden size={16} />
                    <AlertTitle as="h4">まもなく失効するポイント</AlertTitle>
                    <AlertDescription className="tabular-nums">
                      {formatNumber(POINTS.expiringSoon)} pt が{" "}
                      {formatJpDate(POINTS.expiringDate)} に失効予定です。
                    </AlertDescription>
                  </Alert>
                </CardContent>
              </Card>
            </section>

            {/* near-limit warning, tone from token */}
            {period.charges.length > 0 && nearLimit && (
              <Alert variant="destructive">
                <IconAlertTriangle aria-hidden size={16} />
                <AlertTitle as="p">ご利用可能額が残りわずかです</AlertTitle>
                <AlertDescription className="tabular-nums">
                  利用可能枠の {formatPercent(usedRatio)} をご利用中です。残り{" "}
                  {yen(remaining)}。
                </AlertDescription>
              </Alert>
            )}

            {/* ============ Category spend ============ */}
            <section aria-labelledby="category-heading">
              <Card>
                <CardHeader>
                  <CardTitle as="h2" id="category-heading" className="text-lg">
                    カテゴリ別ご利用
                  </CardTitle>
                  <CardDescription>
                    {period.label}・新規ご利用 {yen(newChargesTotal)} の内訳
                  </CardDescription>
                </CardHeader>
                <CardContent>
                  {period.charges.length === 0 ? (
                    <p className="py-8 text-center text-sm text-muted-foreground">
                      この期間のご利用はありません。
                    </p>
                  ) : (
                    <div className="grid items-center gap-6 md:grid-cols-[auto_1fr]">
