"use client";

import * as React from "react";
import {
  Alert,
  AlertDescription,
  Badge,
  Button,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  DialogTrigger,
  Label,
  RadioGroup,
  RadioGroupItem,
  Separator,
  ToggleGroup,
  ToggleGroupItem,
  formatCurrency,
} from "@gunjo/ui";
import { IconCreditCardPay } from "@tabler/icons-react";
import {
  PAYMENT_LABELS,
  quoteMethod,
  type PaymentType,
} from "./card-data";

const BUNKATSU_COUNTS = [3, 6, 10, 12];

export default function PaymentMethodDialog({
  newChargesTotal,
  current,
  onApply,
}: {
  newChargesTotal: number;
  current: PaymentType;
  onApply: (method: PaymentType) => void;
}) {
  const [open, setOpen] = React.useState(false);
  const [method, setMethod] = React.useState<PaymentType>(current);
  const [bunkatsuCount, setBunkatsuCount] = React.useState(6);

  // Re-sync the draft whenever the dialog opens against the live value.
  React.useEffect(() => {
    if (open) setMethod(current);
  }, [open, current]);

  const quote = React.useMemo(
    () => quoteMethod(newChargesTotal, method, bunkatsuCount),
    [newChargesTotal, method, bunkatsuCount],
  );

  function apply() {
    onApply(method);
    setOpen(false);
  }

  return (
    <Dialog open={open} onOpenChange={setOpen}>
      <DialogTrigger asChild>
        <Button variant="outline" size="sm">
          <IconCreditCardPay aria-hidden size={16} className="mr-1.5" />
          支払い方法を変更
        </Button>
      </DialogTrigger>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>お支払い方法の変更</DialogTitle>
          <DialogDescription>
            今回の新規ご利用分{" "}
            <span className="font-semibold text-foreground tabular-nums">
              {formatCurrency(newChargesTotal)}
            </span>{" "}
            のお支払い方法を選択してください。手数料の目安をその場で確認できます。
          </DialogDescription>
        </DialogHeader>

        <RadioGroup
          value={method}
          onValueChange={(v) => setMethod(v as PaymentType)}
          aria-label="お支払い方法"
          className="gap-3"
        >
          {(["ikkatsu", "bunkatsu", "ribo"] as PaymentType[]).map((m) => (
            <div
              key={m}
              className="flex items-start gap-3 rounded-lg border border-border p-3"
            >
              <RadioGroupItem value={m} id={`method-${m}`} className="mt-0.5" />
              <Label htmlFor={`method-${m}`} className="flex-1 cursor-pointer">
                <span className="font-medium text-foreground">
                  {PAYMENT_LABELS[m]}払い
                </span>
                <span className="mt-0.5 block text-xs font-normal text-muted-foreground">
                  {m === "ikkatsu" && "手数料なし。翌月に全額をお支払い。"}
                  {m === "bunkatsu" && "回数を選んで分割。所定の分割手数料。"}
                  {m === "ribo" && "毎月一定額 + 実質年率15.0%の手数料。"}
                </span>
              </Label>
            </div>
          ))}
        </RadioGroup>

        {method === "bunkatsu" && (
          <div className="flex flex-col gap-1.5">
            <Label htmlFor="bunkatsu-count">分割回数</Label>
            <ToggleGroup
              type="single"
              value={String(bunkatsuCount)}
              onValueChange={(v) => v && setBunkatsuCount(Number(v))}
              aria-label="分割回数"
              disallowEmpty
              id="bunkatsu-count"
            >
              {BUNKATSU_COUNTS.map((n) => (
                <ToggleGroupItem key={n} value={String(n)}>
                  {n}回
                </ToggleGroupItem>
              ))}
            </ToggleGroup>
          </div>
        )}

        <Separator />

        <dl className="grid grid-cols-2 gap-x-4 gap-y-2 text-sm" aria-live="polite">
          <dt className="text-muted-foreground">手数料 (目安)</dt>
          <dd className="text-right font-semibold tabular-nums text-foreground">
            {quote.fee === 0 ? "—" : formatCurrency(quote.fee)}
          </dd>
          <dt className="text-muted-foreground">
            {method === "bunkatsu" ? "初回お支払い" : "毎月のお支払い"}
          </dt>
          <dd className="text-right font-semibold tabular-nums text-foreground">
            {formatCurrency(quote.firstPayment)}
          </dd>
        </dl>

        <Alert variant={method === "ikkatsu" ? "info" : "warning"}>
          <AlertDescription>{quote.note}</AlertDescription>
        </Alert>

        <DialogFooter>
          <Button variant="ghost" onClick={() => setOpen(false)}>
            キャンセル
          </Button>
          <Button onClick={apply}>
            この方法に変更
            {method !== "ikkatsu" && (
              <Badge variant="warning" className="ml-2">
                手数料あり
              </Badge>
            )}
          </Button>
        </DialogFooter>
      </DialogContent>
    </Dialog>
  );
}

