/* ------------------------------------------------------------------ */
/* 支払区分 badge — text label inside, so colour is never the only cue. */
/* ------------------------------------------------------------------ */

function PaymentBadge({ charge }: { charge: Charge }) {
  const label =
    charge.payment === "bunkatsu" && charge.installments
      ? `分割 ${charge.installments}回`
      : PAYMENT_LABELS[charge.payment];
  return (
    <Badge variant={PAYMENT_BADGE[charge.payment]} className="font-medium">
      {label}
    </Badge>
  );
}

/* ------------------------------------------------------------------ */
/* Desktop: DataTable. Sortable columns get an auto sort-button +      */
/* aria-sort + <th scope="col"> from the DS; we pass string headers.   */
