/* ------------------------------------------------------------------ */
/* Mobile: stacked cards (DataTable only h-scrolls a 720px table at    */
/* 375px, see FINDINGS F1). Same data + a shared sort control.         */
/* ------------------------------------------------------------------ */

type SortKey = "date" | "amount";
type SortDir = "asc" | "desc";

function MobileChargeList({ charges }: { charges: Charge[] }) {
  const [sortKey, setSortKey] = React.useState<SortKey>("date");
  const [sortDir, setSortDir] = React.useState<SortDir>("desc");

  const sorted = React.useMemo(() => {
    const copy = [...charges];
    copy.sort((a, b) => {
      const av = sortKey === "date" ? a.date : a.amount;
      const bv = sortKey === "date" ? b.date : b.amount;
      const cmp = av < bv ? -1 : av > bv ? 1 : 0;
      return sortDir === "asc" ? cmp : -cmp;
    });
    return copy;
  }, [charges, sortKey, sortDir]);

  function toggle(key: SortKey) {
    if (sortKey === key) {
      setSortDir((d) => (d === "asc" ? "desc" : "asc"));
    } else {
      setSortKey(key);
      setSortDir("desc");
    }
  }

  return (
    <div className="sm:hidden">
      <div
        className="mb-3 flex items-center gap-2"
        role="group"
        aria-label="ご利用明細の並び替え"
      >
        <span className="text-xs text-muted-foreground">並び替え:</span>
        <Button
          variant={sortKey === "date" ? "secondary" : "ghost"}
          size="sm"
          onClick={() => toggle("date")}
          aria-pressed={sortKey === "date"}
        >
          ご利用日 {sortKey === "date" ? (sortDir === "asc" ? "↑" : "↓") : ""}
        </Button>
        <Button
          variant={sortKey === "amount" ? "secondary" : "ghost"}
          size="sm"
          onClick={() => toggle("amount")}
          aria-pressed={sortKey === "amount"}
        >
          金額 {sortKey === "amount" ? (sortDir === "asc" ? "↑" : "↓") : ""}
        </Button>
      </div>
      <ul className="flex flex-col gap-3">
        {sorted.map((c) => (
          <li
            key={c.id}
            className="rounded-lg border border-border bg-card p-4 shadow-sm"
          >
            <div className="flex items-start justify-between gap-3">
              <div className="min-w-0">
                <p className="truncate font-medium text-foreground">
                  {c.merchant}
                </p>
                <p className="mt-0.5 text-xs text-muted-foreground tabular-nums">
                  {formatJpDateShort(c.date)} ・ {CATEGORY_LABELS[c.category]}
                </p>
              </div>
              <p className="shrink-0 text-right font-semibold tabular-nums text-foreground">
                {formatCurrency(c.amount)}
              </p>
            </div>
            <Separator className="my-3" />
            <div className="flex items-center justify-between">
              <PaymentBadge charge={c} />
              <span className="text-xs text-muted-foreground">
                ID&nbsp;{c.id.toUpperCase()}
              </span>
            </div>
          </li>
        ))}
      </ul>
    </div>
  );
}

